import React from 'react';
import { Link } from 'react-router-dom';
import './Sidebar.css';

const Sidebar = () => {
  return (
    <div className="sidebar">
      <h2>CalcFusion</h2>
      <nav>
        <ul>
          <li><Link to="/">Home</Link></li>
          <li><Link to="/emi">EMI Calculator</Link></li>
          <li><Link to="/currency">Currency Converter</Link></li>
          <li><Link to="/salary">Salary Calculator</Link></li>
          <li><Link to="/roi">ROI/NPV Calculator</Link></li>
          <li><Link to="/electricity">Electricity Calculator</Link></li>
          <li><Link to="/dashboard">Dashboard</Link></li>
        </ul>
      </nav>
    </div>
  );
};

export default Sidebar;
